// ============================================================
// CODE NODE — Moteur AFD + Compteurs temporels
// Mini-SIEM CY-01 | ENSAM Casablanca 2025-2026
// ============================================================

const NOW = Date.now();

const PARAMS = {
  Nauth:  3,
  Wauth:  5  * 60 * 1000,
  Treset: 15 * 60 * 1000,
};

// --- Lecture du log depuis le Webhook ---
const inputData = $('Webhook — Réception Logs').first();
let log = inputData.json || inputData.body || inputData;
if (log && log.body && typeof log.body === 'object') log = log.body;
if (typeof log === 'string') { try { log = JSON.parse(log); } catch(e) {} }

const ip        = log?.ip_source || log?.ipSource || log?.ip || log?.source_ip;
const eventType = log?.event_type || log?.eventType || log?.type;

if (!ip || !eventType) {
  throw new Error('Log invalide : ip_source et event_type sont obligatoires.');
}

// --- Récupération du DERNIER état valide depuis Google Sheets ---
let prevState      = 'q0';
let authFailCount  = 0;
let stateEnteredAt = NOW;

try {
  const allRows = $('Get row(s) in sheet').all();
  console.log('Nombre total de lignes:', allRows.length);

  // Filtrer par IP et lignes valides
  const validRows = allRows.filter(r =>
    r.json &&
    r.json.ip_source === ip &&
    r.json.state_after &&
    r.json.state_after.trim() !== ''
  );

  console.log('Lignes valides pour IP', ip, ':', validRows.length);

  if (validRows.length > 0) {
    const lastRow = validRows[validRows.length - 1].json;
    console.log('DERNIERE LIGNE:', JSON.stringify(lastRow));

    prevState      = lastRow.state_after || 'q0';
    authFailCount  = parseInt(lastRow.auth_fail_count) || 0;
    stateEnteredAt = parseInt(lastRow.stateEnteredAt) || NOW;
  }
} catch(e) {
  console.log('Pas de données précédentes:', e.message);
}

// --- Timeout ---
const timeInState = NOW - stateEnteredAt;
if (timeInState > PARAMS.Treset && prevState !== 'q0' && prevState !== 'q3') {
  prevState      = 'q0';
  authFailCount  = 0;
  stateEnteredAt = NOW;
}

// --- Traduction log → symbole AFD ---
let symbol = 'n';
if (eventType === 'auth_fail') {
  authFailCount++;
  console.log('AUTH FAIL COUNT:', authFailCount, '/ Nauth:', PARAMS.Nauth);
  if (authFailCount >= PARAMS.Nauth) symbol = 'b';
} else if (eventType === 'port_scan' || eventType === 'nmap_scan') {
  symbol = 's';
  authFailCount = 0;
} else if (eventType === 'privilege_escalation' || eventType === 'sudo' || eventType === 'su_root') {
  symbol = 'p';
} else if (eventType === 'alert_ack' || eventType === 'reset') {
  symbol = 'r';
  authFailCount = 0;
}

// --- Table de transition δ ---
const DELTA = {
  q0: { b:'q1', s:'q0', p:'q0', n:'q0', r:'q0' },
  q1: { b:'q1', s:'q2', p:'q1', n:'q1', r:'q1' },
  q2: { b:'q2', s:'q2', p:'q3', n:'q2', r:'q2' },
  q3: { b:'q3', s:'q3', p:'q3', n:'q3', r:'q0' },
};

const nextState         = DELTA[prevState]?.[symbol] || prevState;
const newStateEnteredAt = nextState !== prevState ? NOW : stateEnteredAt;

// --- Labels ---
const STATE_LABELS = { q0:'Calme', q1:'Suspect', q2:'Attaque_En_Cours', q3:'Compromis' };

console.log('TRANSITION:', prevState, '--[' + symbol + ']--> ', nextState);

return [{
  json: {
    ip_source:       ip,
    event_type:      eventType,
    symbol:          symbol,
    state_before:    prevState,
    state_after:     nextState,
    current_label:   STATE_LABELS[nextState],
    auth_fail_count: authFailCount,
    is_alert:        nextState === 'q3' && prevState !== 'q3',
    is_q3:           nextState === 'q3',
    stateEnteredAt:  newStateEnteredAt,
    timestamp:       new Date(NOW).toISOString(),
  }
}];

// ============================================================
// CODE NODE — Reset AFD (q3 → q0)
// Mini-SIEM CY-01 | ENSAM Casablanca 2025-2026
// ============================================================

const NOW = Date.now();

// --- 1. Lecture robuste de l'IP (Même logique que le nœud principal) ---
const inputData = $input.first();
let log = inputData.json || inputData.body || inputData;

// Si n8n encapsule dans .body, on descend d'un niveau
if (log && log.body && typeof log.body === 'object') {
    log = log.body;
}

const ip = log?.ip_source || log?.ipSource || log?.ip || log?.source_ip;

if (!ip) {
    throw new Error("Impossible de réinitialiser : 'ip_source' est manquant dans l'entrée.");
}

// --- 2. Accès robuste à la mémoire (StaticData ou Global) ---
const stateStore = (typeof $workflow !== 'undefined' && $workflow && $workflow.staticData)
  ? $workflow.staticData
  : (typeof globalThis !== 'undefined' 
      ? (globalThis.__miniSiemState = globalThis.__miniSiemState || {}) 
      : {});

// --- 3. Logique de réinitialisation (Symbole 'r') ---
if (stateStore.ipContexts && stateStore.ipContexts[ip]) {
    const ctx = stateStore.ipContexts[ip];

    const prevState = ctx.state;
    ctx.state = 'q0';
    ctx.authFailTimes = [];
    ctx.stateEnteredAt = NOW;

    // Ajout à l'historique pour traçabilité SOC
    ctx.eventHistory.push({ 
        time: NOW, 
        event: 'r', 
        from: prevState, 
        to: 'q0', 
        reason: 'Alerte acquittée par SOC (Reset)' 
    });

    // Sauvegarde
    stateStore.ipContexts[ip] = ctx;
}

// --- 4. Sortie pour le Webhook Response ---
return [{ 
    json: { 
        status: 'reset', 
        ip_source: ip, 
        state_before: 'q3',
        state_after: 'q0',
        message: 'AFD réinitialisé à q0. Système en mode Calme.' 
    } 
}];
